import { ArrowUpRight, Activity, Github, RefreshCw } from "lucide-react";
import { motion } from "framer-motion";
import { Link } from "react-router-dom";
import { CMD_KEY_CHIP } from "@/lib/platform";
import { stats as mockStats } from "@/lib/mockData";
import { Reveal } from "./motion";
import { useMarket } from "@/lib/MarketContext";
import { useWorkerHealth } from "@/lib/useWorkerHealth";
import { CountUp, PriceMorph } from "./CountUp";
import Magnetic from "./Magnetic";

export default function Hero() {
  const { market, loading, error } = useMarket();
  const workerHealth = useWorkerHealth();
  const live = market?.stats;
  const isLive = !loading.market && !error.market && !!live && workerHealth.status !== "down";

  return (
    <section
      data-testid="hero-section"
      className="relative min-h-screen pt-32 pb-24 overflow-hidden noise-overlay"
    >
      <div className="absolute inset-0 bg-grid-animated opacity-30 md:opacity-50 [mask-image:radial-gradient(ellipse_at_center,_black_30%,_transparent_75%)]"></div>

      <motion.div
        className="absolute -top-32 -right-32 w-[600px] h-[600px] bg-emerald-500/10 blur-[120px] rounded-full hidden md:block"
        animate={{ scale: [1, 1.1, 1], opacity: [0.6, 1, 0.6] }}
        transition={{ duration: 8, repeat: Infinity, ease: "easeInOut" }}
      />
      <motion.div
        className="absolute top-1/3 -left-32 w-[500px] h-[500px] bg-amber-500/10 blur-[140px] rounded-full hidden md:block"
        animate={{ scale: [1.1, 1, 1.1], opacity: [0.5, 0.9, 0.5] }}
        transition={{ duration: 10, repeat: Infinity, ease: "easeInOut" }}
      />

      <div className="relative max-w-7xl mx-auto px-6 md:px-12 lg:px-16 z-10">
        <motion.div
          className="flex items-center gap-3 mb-10 flex-wrap"
          initial={{ opacity: 0, y: -10 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6, delay: 0.1 }}
        >
          <div className="inline-flex items-center gap-2.5 bg-white/[0.04] border border-white/10 rounded-full px-4 py-1.5 backdrop-blur-md">
            <span className="relative flex h-2 w-2">
              {isLive && <span className="absolute inline-flex h-full w-full rounded-full bg-emerald-400 opacity-75 animate-ping"></span>}
              <span className={`relative inline-flex rounded-full h-2 w-2 ${isLive ? "bg-emerald-500" : "bg-amber-500"}`}></span>
            </span>
            <span
              data-testid="hero-live-status"
              className={`inline-flex items-center gap-1.5 text-[11px] font-mono uppercase tracking-[0.2em] transition-colors duration-500 ${isLive ? "text-emerald-300" : workerHealth.status === "down" ? "text-red-300" : "text-amber-300"}`}
            >
              <span className="w-3 h-3 inline-grid place-items-center shrink-0" aria-hidden="true">
                {loading.market && <RefreshCw data-testid="hero-refreshing" className="w-3 h-3 animate-spin" />}
              </span>
              <span className="w-[200px] tabular-nums text-left truncate">
                {loading.market
                  ? "Connecting · CMI Worker"
                  : workerHealth.status === "down"
                    ? "Worker unreachable"
                    : error.market
                      ? "Cached · API unreachable"
                      : `Last sync · ${live?.lastUpdated || "—"}${workerHealth.latencyMs != null ? ` · ${workerHealth.latencyMs}ms` : ""}`}
              </span>
            </span>
          </div>
          <span className="hidden sm:inline-block text-[11px] font-mono uppercase tracking-[0.2em] text-zinc-500">
            v2.4 / castia worker
          </span>
          <span className="hidden md:inline-flex items-center gap-2 text-[11px] font-mono uppercase tracking-[0.2em] text-zinc-500 ml-auto">
            Press <span className="inline-flex items-center gap-1"><span className="kbd">{CMD_KEY_CHIP}</span><span className="kbd">k</span></span> to search · <span className="kbd">?</span> shortcuts
          </span>
        </motion.div>

        <div className="max-w-5xl">
          <motion.h1
            data-testid="hero-headline"
            className="font-heading text-5xl sm:text-7xl lg:text-[8rem] leading-[0.92] tracking-tighter font-black uppercase"
            initial={{ opacity: 0, y: 30 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 1, delay: 0.2, ease: [0.16, 1, 0.3, 1] }}
          >
            The price of
            <br />
            <span className="inline-flex items-baseline gap-4">
              <span className="text-emerald-400">every</span>
              <span className="inline-block bg-emerald-400 text-bg-base px-2 -mb-1 align-middle">item</span>
            </span>
            <br />
            on Castia.
          </motion.h1>

          <motion.p
            data-testid="hero-subtext"
            className="mt-10 max-w-2xl text-lg sm:text-xl text-zinc-400 leading-relaxed font-light"
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.8, delay: 0.5 }}
          >
            Median prices, confidence ratings, and IQR ranges from the Castia
            auction house — ranked and refreshed every five minutes. Trade
            smarter. Never overpay again.
          </motion.p>
        </div>

        <motion.div
          className="mt-12 flex flex-col sm:flex-row items-start sm:items-center gap-4"
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8, delay: 0.7 }}
        >
          <Magnetic>
            <Link
              data-testid="hero-launch-btn"
              to="/listings"
              className="group inline-flex items-center gap-3 bg-emerald-500 hover:bg-emerald-400 text-black font-bold uppercase tracking-[0.2em] text-sm px-7 py-4 rounded-sm transition-all active:scale-95 hover:shadow-[0_0_40px_rgba(16,185,129,0.5)]"
            >
              <Activity className="w-4 h-4" />
              Launch live tracker
              <ArrowUpRight className="w-4 h-4 group-hover:translate-x-0.5 group-hover:-translate-y-0.5 transition-transform" />
            </Link>
          </Magnetic>
          <a
            data-testid="hero-github-btn"
            href="#how"
            className="group inline-flex items-center gap-3 border border-white/15 hover:border-white/40 hover:bg-white/[0.03] text-white font-medium uppercase tracking-[0.18em] text-sm px-7 py-4 rounded-sm transition-all"
          >
            <Github className="w-4 h-4" />
            See how it works
          </a>
        </motion.div>

        <Reveal delay={0.9} className="mt-20">
          <div className="grid grid-cols-2 md:grid-cols-4 gap-px bg-white/10 border border-white/10 rounded-lg overflow-hidden backdrop-blur-xl">
            <HeroStat label="Items tracked" value={live ? live.totalItems : mockStats.totalItems} loading={loading.market} />
            <HeroStat label="Categories" value={live ? live.categories : mockStats.categories} loading={loading.market} />
            <div className="bg-bg-base/80 px-6 py-6">
              <div className="font-mono text-[10px] uppercase tracking-[0.25em] text-zinc-500 mb-2">Refresh rate</div>
              <div className="font-heading font-extrabold text-2xl sm:text-3xl text-white tabular">5 min</div>
            </div>
            <div className="bg-bg-base/80 px-6 py-6">
              <div className="font-mono text-[10px] uppercase tracking-[0.25em] text-zinc-500 mb-2">Highest median</div>
              <div className="font-heading font-extrabold text-2xl sm:text-3xl text-white">
                {loading.market ? (
                  <span className="inline-block h-7 w-20 bg-white/5 rounded animate-pulse" />
                ) : (
                  <PriceMorph value={live ? live.highestPriceRaw : 75_000_000} />
                )}
              </div>
            </div>
          </div>
        </Reveal>
      </div>
    </section>
  );
}

function HeroStat({ label, value, loading }) {
  return (
    <div className="bg-bg-base/80 px-6 py-6">
      <div className="font-mono text-[10px] uppercase tracking-[0.25em] text-zinc-500 mb-2">{label}</div>
      <div className="font-heading font-extrabold text-2xl sm:text-3xl text-white">
        {loading ? (
          <span className="inline-block h-7 w-20 bg-white/5 rounded animate-pulse" />
        ) : (
          <CountUp value={value} format={(v) => v.toLocaleString()} duration={1.2} />
        )}
      </div>
    </div>
  );
}
