// Lightweight worker health probe. Pings fetchSellers() (cheap, no rate-limit
// impact) on mount and every 60s, tracks latency, and classifies health.
// Used by the Hero live-status dot so it reflects real worker reachability,
// not just "do we have any market data cached".

import { useEffect, useState } from "react";
import { fetchSellers } from "./castiaClient";

const PROBE_INTERVAL = 60_000;
// 'healthy' is sticky between probes so the dot doesn't flicker during
// in-flight requests — we only flip on a confirmed 'down'.
export function useWorkerHealth() {
  const [health, setHealth] = useState({ status: "unknown", latencyMs: null, lastCheckedMs: 0 });

  useEffect(() => {
    let cancelled = false;
    const probe = async () => {
      const start = performance.now();
      try {
        await fetchSellers();
        if (cancelled) return;
        const latencyMs = Math.round(performance.now() - start);
        setHealth((prev) => ({
          status: prev.status === "down" ? "healthy" : "healthy",
          latencyMs,
          lastCheckedMs: Date.now(),
        }));
      } catch {
        if (cancelled) return;
        setHealth((prev) => ({ status: "down", latencyMs: prev.latencyMs, lastCheckedMs: Date.now() }));
      }
    };
    probe();
    const id = setInterval(probe, PROBE_INTERVAL);
    return () => {
      cancelled = true;
      clearInterval(id);
    };
  }, []);

  return health;
}
